      status: _readRequiredString(json, "status"),
      lastVerifiedAt: _readOptionalString(json, "lastVerifiedAt"),
      metaData: _readRequiredObject(json, "metaData"),
      isSoftDeleted: _readRequiredBool(json, "isSoftDeleted"),
      createdAt: _readRequiredString(json, "createdAt"),
      updatedAt: _readRequiredString(json, "updatedAt"),
      createdBy: _readOptionalString(json, "createdBy"),
      updatedBy: _readOptionalString(json, "updatedBy"),
    );
  }

  Map<String, Object?> toJson() => <String, Object?>{
    "id": id,
    "repoUrl": repoUrl,
    "displayName": displayName,
    "provider": provider,
    "defaultBranch": defaultBranch,
    "status": status,
    "lastVerifiedAt": lastVerifiedAt,
    "metaData": metaData,
    "isSoftDeleted": isSoftDeleted,
    "createdAt": createdAt,
    "updatedAt": updatedAt,
    "createdBy": createdBy,
    "updatedBy": updatedBy,
  };

  List<String> validate() {
    final errors = <String>[];
    if (!RegExp(r'^(git@|ssh://|https://).+').hasMatch(repoUrl)) {
      errors.add("known_git_repos.repo_url does not match the required pattern");
    }
    if (utf8.encode(repoUrl).length > 2048) {
      errors.add("known_git_repos.repo_url exceeds 2048 bytes");
    }
    if (utf8.encode(displayName).length > 200) {
      errors.add("known_git_repos.display_name exceeds 200 bytes");
    }
    if (!knownGitRepoProviderValues.contains(provider)) {
      errors.add("unsupported known_git_repos.provider");
    }
    if (!RegExp(r'^[A-Za-z0-9._/-]{1,120}$').hasMatch(defaultBranch)) {
      errors.add("known_git_repos.default_branch does not match the required pattern");
    }
    if (!knownGitRepoStatusValues.contains(status)) {
      errors.add("unsupported known_git_repos.status");
    }
    return errors;
  }
}

